document.addEventListener('change',e=>{if(e.target.id==='docLogoInput'){const file=e.target.files&&e.target.files[0];if(!file)return;const reader=new FileReader();reader.onload=()=>{const d=ensureSettingsDraft();d.docLogo=reader.result;markSettingsDirty();toast('Document logo loaded — save changes to keep it');render()};reader.readAsDataURL(file)}if(e.target.id==='importFileInput')handleImportFile(e)});
document.addEventListener('input',e=>{if(e.target.id==='searchInput'){state.search=e.target.value.trim();save();render()}if(e.target.closest&&e.target.closest('#settingsForm')){const d=ensureSettingsDraft();d[e.target.name]=e.target.value;markSettingsDirty()}});
function exportData(){
  const backup={version:'1.0',date:new Date().toISOString().slice(0,10),data:JSON.parse(JSON.stringify(state))};
  const blob=new Blob([JSON.stringify(backup,null,2)],{type:'application/json'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;a.download=`TradeAssist_backup_${new Date().toISOString().slice(0,10)}.json`;a.click();
  URL.revokeObjectURL(url);toast('Backup downloaded');
}
function handleImportFile(e){
  const file=e.target.files&&e.target.files[0];
  if(!file)return;
  const reader=new FileReader();
  reader.onload=()=>{
    try{
      const backup=JSON.parse(reader.result);
      if(!backup||!backup.version||!backup.data){toast('Invalid backup file');return;}
      const d=backup.data;
      const summary=`Leads: ${d.leads?.length||0} | Quotes: ${d.quotes?.length||0} | Invoices: ${d.invoices?.length||0} | Bookings: ${d.bookings?.length||0}`;
      if(confirm(`Restore this backup?\n\n${summary}\n\nThis will replace all current data.`)){
        state.leads=d.leads||[];
        state.quotes=d.quotes||[];
        state.invoices=d.invoices||[];
        state.bookings=d.bookings||[];
        state.customers=d.customers||[];
        state.messages=d.messages||[];
        state.followups=d.followups||[];
        if(d.settings)state.settings={...state.settings,...d.settings};
        save();toast('Backup restored');render();
      }
    }catch{toast('Could not read backup file');}
    e.target.value='';
  };
  reader.readAsText(file);
}
function renderClock(){document.getElementById('clockChip').textContent=new Date().toLocaleString([],{weekday:'short',hour:'numeric',minute:'2-digit'})}
load();state.theme=state.settings.theme||state.theme||'ocean';document.getElementById('searchInput').value=state.search||'';render();renderClock();setInterval(renderClock,60000)